from haystack import component

@component
class SafetyFilter:
    @component.output_types(response=str, safe=bool)
    def run(self, text: str) -> dict:
        import re
        pii_pattern = r'\b(?:\d{3}-?\d{2}-?\d{4}|\w+@\w+\.\w+)\b'
        safe_text = re.sub(pii_pattern, '[REDACTED]', text)
        is_safe = 'harmful' not in safe_text.lower()
        return {"response": safe_text, "safe": is_safe}

