from vex_sdk import Vex
from haystack import component

@component
class VexVerifier:
    def __init__(self):
        self.vex = Vex(api_key="vex-api-key")

    @component.output_types(verified_response=str, score=float, passed=bool)
    def run(self, query: str, documents: list, response: str) -> dict:
        result = self.vex.verify(
            task='rag_verification',
            inputs={'query': query, 'context': documents, 'response': response},
            checks=['hallucination', 'relevance', 'safety']
        )
        return {
            'verified_response': response if result.passed else 'Blocked',
            'score': result.score,
            'passed': result.passed
        }

chat_pipeline.add_component("vex_coherence", VexVerifier())
chat_pipeline.connect("memory.output", "vex_coherence.context")
chat_pipeline.connect("generator.replies", "vex_coherence.response")
chat_pipeline.connect("memory.current_query", "vex_coherence.query")

